{
  "executive_summary": "Option B (event-driven with a message queue) is the recommended architecture. It naturally satisfies the reliability requirement through message persistence and retry semantics, accommodates new channels without modifying the delivery service, and fits the 5-minute latency tolerance. However, given the 3-engineer team constraint, the implementation must use a managed queue service (SQS, Cloud Tasks, or equivalent) rather than self-hosted infrastructure like RabbitMQ or Kafka.",

  "architecture": {
    "components": [
      {
        "name": "Delivery Service",
        "responsibility": "Manages delivery lifecycle (pickup, in-transit, delivered). Publishes domain events when delivery status changes. Has zero knowledge of notification channels.",
        "boundaries": "Owns delivery aggregate. Only dependency is the message queue SDK. Never imports notification logic."
      },
      {
        "name": "Message Queue (Managed)",
        "responsibility": "Durably stores domain events. Provides at-least-once delivery with visibility timeout and dead-letter queue (DLQ) support.",
        "boundaries": "Infrastructure component. AWS SQS, Google Cloud Tasks, or Azure Service Bus. Team does NOT self-host."
      },
      {
        "name": "Notification Worker",
        "responsibility": "Consumes delivery events from the queue. Resolves customer notification preferences. Dispatches to channel-specific providers (email, SMS). Handles retries and circuit-breaking per provider.",
        "boundaries": "Owns notification dispatch logic. Depends on Channel Provider abstractions, not concrete provider SDKs directly."
      },
      {
        "name": "Channel Providers (Email, SMS, future: Push, WhatsApp)",
        "responsibility": "Thin adapters wrapping third-party APIs (SendGrid, Twilio, etc.). Each implements a common NotificationChannel interface.",
        "boundaries": "One adapter per provider. Swappable. No business logic — only API translation and error mapping."
      },
      {
        "name": "Dead-Letter Queue + Alert",
        "responsibility": "Captures messages that fail all retry attempts. Triggers an alert (email/Slack to ops) so failures are never silently dropped.",
        "boundaries": "Managed queue feature. No custom code beyond the alert hook."
      }
    ],
    "interfaces": [
      {
        "from": "Delivery Service",
        "to": "Message Queue",
        "contract": "Publishes DeliveryStatusChanged event: { deliveryId, customerId, status, timestamp, metadata }. JSON serialized. Schema-versioned with a 'version' field.",
        "coupling_type": "loose — fire-and-forget publish, no response expected"
      },
      {
        "from": "Message Queue",
        "to": "Notification Worker",
        "contract": "Worker polls or receives push of DeliveryStatusChanged events. Acknowledges after successful dispatch to all required channels. Visibility timeout = 60s.",
        "coupling_type": "loose — temporal decoupling via queue"
      },
      {
        "from": "Notification Worker",
        "to": "Channel Providers",
        "contract": "NotificationChannel interface: send(recipient: ContactInfo, message: NotificationPayload): Result<Success, ChannelError>. Each provider implements this interface.",
        "coupling_type": "loose — polymorphic dispatch behind interface"
      }
    ],
    "data_flow": "Delivery Service mutates delivery state → publishes DeliveryStatusChanged to queue → Notification Worker consumes event → resolves customer preferences (which channels?) → fans out to relevant Channel Providers → on success: ACK message → on failure: message returns to queue after visibility timeout → after N failures: message moves to DLQ → DLQ triggers ops alert.",
    "patterns_used": [
      {
        "pattern": "Domain Events via Message Queue",
        "rationale": "Decouples the delivery domain from notification concerns. The delivery service doesn't need to know how many channels exist or how to reach them. New channels are added by deploying new adapters — zero changes to the publisher."
      },
      {
        "pattern": "Strategy Pattern (Channel Providers)",
        "rationale": "Each notification channel implements a common interface. The worker selects strategies at runtime based on customer preferences. Adding WhatsApp means adding one new class — no conditionals modified."
      },
      {
        "pattern": "Dead-Letter Queue",
        "rationale": "Directly satisfies the 'never silently drop' requirement. Messages that exhaust retries land in the DLQ where they are visible and alertable, not lost."
      },
      {
        "pattern": "Idempotent Consumer",
        "rationale": "At-least-once delivery means duplicates are possible. The worker must be idempotent — track (deliveryId + status + channel) to skip already-sent notifications. A simple database uniqueness constraint suffices."
      },
      {
        "pattern": "Transactional Outbox (optional, phase 2)",
        "rationale": "If the team later needs guaranteed event publishing (no event lost even if the service crashes between DB commit and queue publish), the outbox pattern can be added. Not needed for MVP given the latency tolerance."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Delivery",
        "classification": "core",
        "aggregates": ["Delivery (root: deliveryId, states: created → picked_up → in_transit → out_for_delivery → delivered → failed_delivery)"]
      },
      {
        "name": "Notification",
        "classification": "supporting",
        "aggregates": ["NotificationRecord (root: notificationId, tracks: deliveryId, channel, status, attempts, lastError)"]
      },
      {
        "name": "Customer",
        "classification": "supporting",
        "aggregates": ["CustomerPreferences (root: customerId, stores: preferred channels, contact info per channel)"]
      }
    ],
    "context_map": [
      {
        "upstream": "Delivery",
        "downstream": "Notification",
        "relationship": "Customer-Supplier via domain events. Delivery defines the event schema. Notification conforms to it. An Anti-Corruption Layer in the Notification worker translates DeliveryStatusChanged into channel-specific message templates."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Option B (event-driven) over Option A (synchronous REST)",
      "gains": "Reliability via queue persistence and automatic retries. Open/Closed for new channels — no delivery service changes needed. Delivery service latency unaffected by slow providers. Partial failure isolation — one channel down doesn't block others.",
      "sacrifices": "Added infrastructure component (managed queue). Slightly more complex debugging (async flow). Team must learn queue semantics (visibility timeout, DLQ, idempotency).",
      "alternatives_considered": [
        "Option A: Synchronous REST — simpler to build initially, but fails the reliability requirement: if the SMS API is down, the delivery service must either block (hurting its own latency) or drop the notification (violating requirements). Retry logic embedded in the delivery service creates tight coupling and makes adding channels increasingly painful.",
        "Hybrid: Synchronous with async retry queue — worst of both worlds. Delivery service still coupled to channels, and you still need the queue anyway for retries."
      ]
    },
    {
      "decision": "Managed queue service over self-hosted (RabbitMQ, Kafka)",
      "gains": "Zero operational burden. No broker patching, scaling, or monitoring. Fits a 3-engineer team. SQS costs pennies at notification volumes.",
      "sacrifices": "Vendor lock-in to cloud provider. Less flexibility in routing topology compared to RabbitMQ exchanges or Kafka topics.",
      "alternatives_considered": [
        "Self-hosted RabbitMQ — powerful but requires operational expertise the team doesn't have. A dead broker means all notifications stop.",
        "Kafka — massive overkill for notification volumes. Designed for high-throughput event streaming, not task dispatch."
      ]
    },
    {
      "decision": "Single notification worker process over per-channel workers",
      "gains": "Simpler deployment and monitoring for a small team. One process, one log stream, one health check.",
      "sacrifices": "A slow channel (e.g., email API timeout) can slow down processing of other channels. Mitigated by async dispatch within the worker and per-channel circuit breakers.",
      "alternatives_considered": [
        "Per-channel worker queues — better isolation but doubles/triples the infrastructure surface. Appropriate when the team grows or volume demands it."
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Adding new notification channels",
      "evolution_path": "Implement a new class conforming to the NotificationChannel interface. Register it in the channel registry. Deploy. No changes to the delivery service or queue infrastructure."
    },
    {
      "area": "Switching providers within a channel",
      "evolution_path": "Swap the adapter behind the interface (e.g., SendGrid → Mailgun). The worker and delivery service are unaffected."
    },
    {
      "area": "Scaling notification throughput",
      "evolution_path": "Add more worker instances consuming from the same queue. SQS supports competing consumers natively. No code changes."
    },
    {
      "area": "Splitting to per-channel queues",
      "evolution_path": "If one channel's volume or failure rate demands isolation, fan-out from the main queue to channel-specific queues. The delivery service still publishes to one topic."
    }
  ],

  "rigidity_points": [
    {
      "area": "Event schema (DeliveryStatusChanged)",
      "reason": "This is the contract between Delivery and Notification contexts. Changes require coordination. Mitigated by schema versioning — always add fields, never remove. Include a 'version' field from day one."
    },
    {
      "area": "At-least-once delivery semantics",
      "reason": "The idempotency requirement is baked into the architecture. Every consumer must handle duplicates. This is a permanent constraint — you cannot remove it without switching to exactly-once infrastructure (which is far more complex)."
    },
    {
      "area": "Managed queue vendor choice",
      "reason": "Switching from SQS to Cloud Tasks requires changing SDK calls in both publisher and consumer. Mitigate by wrapping queue operations behind a thin abstraction, but don't over-engineer this — the team is small."
    }
  ],

  "risks": [
    {
      "risk": "Poison message: a malformed event repeatedly fails and blocks the worker",
      "severity": "high",
      "mitigation": "Configure maxReceiveCount on the queue (e.g., 5 attempts). After exhaustion, the message moves to the DLQ automatically. Worker should catch and log all exceptions — never let an unhandled error cause a crash loop."
    },
    {
      "risk": "Duplicate notifications sent to customers",
      "severity": "medium",
      "mitigation": "Implement idempotency key: (deliveryId, status, channel). Before sending, check if this combination was already dispatched. A simple DB unique constraint or Redis SET NX suffices."
    },
    {
      "risk": "DLQ grows unnoticed and notifications are silently lost in practice",
      "severity": "high",
      "mitigation": "Set up a CloudWatch alarm (or equivalent) on DLQ message count > 0. Route alert to the team's Slack channel. Review DLQ messages weekly as an operational habit."
    },
    {
      "risk": "Event published but DB transaction rolled back (delivery state inconsistent with published event)",
      "severity": "medium",
      "mitigation": "For MVP: publish event after DB commit — accept the small window where a crash between commit and publish loses the event. For phase 2: adopt the Transactional Outbox pattern if this proves to be a real problem."
    },
    {
      "risk": "Team unfamiliar with async patterns — debugging is harder than synchronous calls",
      "severity": "medium",
      "mitigation": "Add correlation IDs (deliveryId) to every log line across the delivery service and notification worker. Use structured logging (JSON). This makes tracing an event through the system trivial with log search."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Phase 1 (week 1-2): Set up managed queue (SQS + DLQ). Implement DeliveryStatusChanged event publishing in the delivery service. Build one notification worker with email channel adapter. Add idempotency tracking. Wire DLQ alarm. Phase 2 (week 3): Add SMS channel adapter. Phase 3 (week 4): Add customer preference lookup so customers can choose channels. Keep the worker as a single process with per-channel async dispatch internally. Do NOT build per-channel queues until volume demands it.",
    "files_to_create_or_modify": [
      "src/delivery/events/delivery-status-changed.ts — Domain event definition with version field",
      "src/delivery/services/delivery-service.ts — Add event publishing after status transitions",
      "src/notifications/worker.ts — Queue consumer, event handler, channel dispatcher",
      "src/notifications/channels/notification-channel.ts — Interface definition",
      "src/notifications/channels/email-adapter.ts — SendGrid/SES adapter",
      "src/notifications/channels/sms-adapter.ts — Twilio adapter",
      "src/notifications/idempotency/notification-record-repository.ts — Tracks sent notifications",
      "src/notifications/templates/template-resolver.ts — Maps (status, channel) to message templates",
      "infra/queue.tf or infra/cdk/ — Queue + DLQ + alarm infrastructure-as-code"
    ],
    "patterns_to_follow": "Use a channel registry (Map<ChannelType, NotificationChannel>) in the worker rather than if/else chains. Each adapter is independently testable by mocking the provider SDK. Write integration tests using a local queue emulator (e.g., ElasticMQ for SQS) or an in-memory queue stub. Keep the event schema flat and serializable — no nested objects beyond one level.",
    "pitfalls_to_avoid": [
      "Do NOT embed retry logic inside the delivery service — that's the queue's job",
      "Do NOT use Kafka or RabbitMQ — the team cannot afford the operational burden",
      "Do NOT build a custom retry/backoff system — use the queue's native retry with exponential backoff via visibility timeout",
      "Do NOT fan out to multiple queues in phase 1 — premature complexity for 3 engineers",
      "Do NOT skip idempotency — at-least-once delivery WILL produce duplicates in production",
      "Do NOT put notification templates in the delivery service — that couples the contexts"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 92,
    "high_confidence_areas": [
      "Option B is clearly superior given the reliability requirement and latency tolerance",
      "Managed queue over self-hosted is the right call for a 3-person team",
      "Strategy pattern for channel extensibility is well-established and low-risk",
      "DLQ + alerting satisfies the never-silently-drop requirement"
    ],
    "low_confidence_areas": [
      "Specific queue vendor choice depends on the team's existing cloud provider, which is unknown",
      "Whether the Transactional Outbox is needed depends on actual failure rates in production — may never be necessary"
    ],
    "assumptions": [
      "The team uses a major cloud provider (AWS, GCP, or Azure) with a managed queue offering",
      "Notification volume is moderate (thousands to low millions per day, not billions)",
      "The delivery service already has a database for its own state",
      "Customer contact information is accessible from the notification context (either owned or queryable)"
    ]
  }
}
